struct Node {
    int starting;
    int no_of_edges;
};

__kernel void
BFS_1(__global struct Node* g_graph_nodes, __global int* g_graph_edges, __global char* g_graph_mask, __global char* g_updating_graph_mask, __global char *g_graph_visited, __global int* v_0, int no_of_nodes) 
{
    int tid = get_global_id(0);
    if( tid < no_of_nodes && g_graph_mask[tid])
    {
        g_graph_mask[tid] = 0;
        for(int i = g_graph_nodes[tid].starting; i < (g_graph_nodes[tid].no_of_edges + g_graph_nodes[tid].starting); i++)
        {
            int id = g_graph_edges[i];
            if(!g_graph_visited[id])
            {
                v_0[id] = v_0[tid] + 1;
                g_updating_graph_mask[id] = 1;
            }
        }
    }
}

__kernel void
BFS_2(__global char* g_graph_mask, __global char *g_updating_graph_mask, __global char* g_graph_visited, __global char *g_over, int no_of_nodes)
{
    int tid = get_global_id(0);
    if( no_of_nodes > tid && g_updating_graph_mask[tid])
    {
        g_graph_mask[tid] = 1;
        g_graph_visited[tid] = 1;
        *g_over = 1;
        g_updating_graph_mask[tid] = 0;
    }
}
